import React, { useState, useEffect, useContext, useRef } from 'react';
import { Globe, ArrowUpRight, ArrowDownRight, Zap, Activity, ShieldCheck, Terminal as TerminalIcon } from 'lucide-react';
import { AuthContext } from '../context/AuthContext';

const LiveMarket = () => {
  const { token } = useContext(AuthContext);
  const [prices, setPrices] = useState({});
  const [logs, setLogs] = useState([]);
  const [status, setStatus] = useState('CONNECTING');
  const scrollRef = useRef(null);

  // 🧪 Add log messages to the terminal feed
  const addLog = (msg) => {
    const timestamp = new Date().toLocaleTimeString().split(' ')[0];
    setLogs(prev => [`[${timestamp}] ${msg}`, ...prev].slice(0, 5));
  };

  useEffect(() => {
    if (!token) return;

    // ── WebSocket Logic ──
    const socket = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);
    
    socket.onopen = () => {
      setStatus('STABLE');
      addLog("NODE_SYNCHRONIZED: Receiving high-frequency stream.");
    };

    socket.onmessage = (event) => {
      const data = JSON.parse(event.data);
      // In a real app, 'data' would contain new prices. 
      // Here, we trigger a "Price Pulse" simulation.
      simulatePriceUpdate();
    };

    socket.onerror = () => setStatus('ERROR');
    socket.onclose = () => setStatus('OFFLINE');

    // Initial mock prices
    const initialPrices = {
      'RELIANCE': { val: 2985.40, change: 1.2 },
      'TCS': { val: 4120.15, change: -0.4 },
      'HDFCBANK': { val: 1640.80, change: 0.8 },
      'INFY': { val: 1710.25, change: 2.1 },
      'ZOMATO': { val: 158.40, change: -1.5 },
      'TATASTEEL': { val: 144.10, change: 0.3 }
    };
    setPrices(initialPrices);

    const simulatePriceUpdate = () => {
      setPrices(prev => {
        const keys = Object.keys(prev);
        const randomKey = keys[Math.floor(Math.random() * keys.length)];
        const movement = (Math.random() - 0.5) * 5;
        const newVal = prev[randomKey].val + movement;
        
        if (Math.abs(movement) > 2) {
            addLog(`VOLATILITY_ALERT: ${randomKey} shifted ${movement > 0 ? '+' : ''}${movement.toFixed(2)}`);
        }
        
        return {
          ...prev,
          [randomKey]: { 
            val: newVal, 
            change: prev[randomKey].change + (movement / 10),
            lastMove: movement > 0 ? 'up' : 'down'
          }
        };
      });
    };

    const interval = setInterval(simulatePriceUpdate, 2000);
    return () => {
        socket.close();
        clearInterval(interval);
    };
  }, [token]);

  return (
    <div className="reveal-node" style={containerStyle}>
      
      {/* ── Header ── */}
      <div style={headerStyle}>
        <div>
          <h2 style={titleStyle}>
            <Globe size={20} color="var(--accent-primary)" /> Live_Pulse_Monitor
          </h2>
          <p style={subtitleStyle}>Region: PUNE_MAH_IN // Protocol: WebSocket_SSL</p>
        </div>
        <div style={statusBadgeStyle(status)}>
          <div style={statusDotStyle(status)} /> {status}
        </div>
      </div>

      {/* ── Market Grid ── */}
      <div style={gridStyle}>
        {Object.entries(prices).map(([ticker, data]) => (
          <PriceCard key={ticker} ticker={ticker} data={data} />
        ))}
      </div>

      {/* ── Interactive Terminal Log ── */}
      <div style={terminalContainerStyle}>
        <div style={terminalHeaderStyle}>
          <TerminalIcon size={14} color="var(--accent-primary)" />
          <span>SYSTEM_LOG_FEED</span>
          <div style={{ marginLeft: 'auto', display: 'flex', gap: '8px' }}>
            <Activity size={12} color="var(--accent-primary)" />
            <span style={{ fontSize: '10px' }}>LATENCY: 12MS</span>
          </div>
        </div>
        <div style={logAreaStyle}>
          {logs.map((log, i) => (
            <div key={i} style={{ color: log.includes('ALERT') ? '#ef4444' : 'var(--text-secondary)', marginBottom: '4px' }}>
              {log}
            </div>
          ))}
          {logs.length === 0 && <div style={{ color: 'var(--text-muted)' }}>AWATING_DATA_PACKETS...</div>}
        </div>
      </div>

    </div>
  );
};

/* ── Sub-Components ── */

const PriceCard = ({ ticker, data }) => {
  const isUp = data.change >= 0;
  return (
    <div style={{
        ...cardStyle,
        borderColor: data.lastMove === 'up' ? 'rgba(16, 185, 129, 0.4)' : data.lastMove === 'down' ? 'rgba(239, 68, 68, 0.4)' : 'var(--surface-border)'
    }}>
      <div style={cardTopStyle}>
        <span style={tickerStyle}>{ticker}</span>
        <Zap size={14} color={isUp ? 'var(--accent-primary)' : '#ef4444'} />
      </div>
      <div style={priceValueStyle}>
        ₹{data.val.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
      </div>
      <div style={{ ...changeStyle, color: isUp ? 'var(--accent-primary)' : '#ef4444' }}>
        {isUp ? <ArrowUpRight size={12} /> : <ArrowDownRight size={12} />}
        {Math.abs(data.change).toFixed(2)}%
      </div>
      
      {/* Mini Visualizer Sparkline Substitute */}
      <div style={sparklineContainerStyle}>
          <div style={{ ...sparklineBarStyle, height: '40%', background: isUp ? 'var(--accent-primary)' : '#ef4444', opacity: 0.3 }} />
          <div style={{ ...sparklineBarStyle, height: '70%', background: isUp ? 'var(--accent-primary)' : '#ef4444', opacity: 0.6 }} />
          <div style={{ ...sparklineBarStyle, height: '50%', background: isUp ? 'var(--accent-primary)' : '#ef4444', opacity: 1 }} />
      </div>
    </div>
  );
};

/* ── Styles ── */

const containerStyle = { flex: 1, padding: '2.5rem 1.5rem', maxWidth: '1200px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '2rem' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid var(--surface-border)', paddingBottom: '1.5rem' };
const titleStyle = { display: 'flex', alignItems: 'center', gap: '12px', color: 'var(--text-primary)', textTransform: 'uppercase', letterSpacing: '0.1em', fontWeight: 800, fontSize: '1.2rem', margin: 0 };
const subtitleStyle = { fontSize: '0.6rem', color: 'var(--text-muted)', letterSpacing: '0.2em', textTransform: 'uppercase', marginTop: '0.5rem' };

const statusBadgeStyle = (status) => ({
    display: 'flex', alignItems: 'center', gap: '8px', padding: '6px 14px', borderRadius: '100px',
    background: 'var(--surface-glass)', border: '1px solid var(--surface-border)',
    color: status === 'STABLE' ? 'var(--accent-primary)' : '#ef4444', fontSize: '0.6rem', fontWeight: 800
});

const statusDotStyle = (status) => ({
    width: '6px', height: '6px', borderRadius: '50%',
    background: status === 'STABLE' ? 'var(--accent-primary)' : '#ef4444',
    boxShadow: status === 'STABLE' ? '0 0 8px var(--accent-glow)' : 'none',
    animation: status === 'STABLE' ? 'pulse 2s infinite' : 'none'
});

const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: '1rem' };
const cardStyle = { padding: '1.5rem', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)', borderRadius: '20px', backdropFilter: 'blur(12px)', transition: 'all 0.4s ease' };
const cardTopStyle = { display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' };
const tickerStyle = { fontWeight: 900, fontSize: '0.9rem', color: 'var(--text-primary)', letterSpacing: '0.05em' };
const priceValueStyle = { fontSize: '1.6rem', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '0.25rem', fontFamily: 'monospace' };
const changeStyle = { display: 'flex', alignItems: 'center', gap: '4px', fontSize: '0.75rem', fontWeight: 700 };

const sparklineContainerStyle = { display: 'flex', alignItems: 'flex-end', gap: '3px', height: '20px', marginTop: '1rem' };
const sparklineBarStyle = { width: '4px', borderRadius: '2px', transition: 'height 0.3s ease' };

